module microprocessor_pad_top(clk_pad, rst_pad, mem_bank_sel_pad,
     dbg_sel_pad, CLKOUT_pad, dbg_out_pad);
  input clk_pad, rst_pad;
  input [1:0] mem_bank_sel_pad, dbg_sel_pad;
  output CLKOUT_pad;
  output [31:0] dbg_out_pad;
  wire clk_pad, rst_pad;
  wire [1:0] mem_bank_sel_pad, dbg_sel_pad;
  wire CLKOUT_pad;
  wire [31:0] dbg_out_pad;
  wire [1:0] dbg_sel;
  wire [1:0] mem_bank_sel;
  wire [31:0] dbg_out;
  wire UNCONNECTED174, clk, rst;
  pfrelr corner_1();
  pfrelr corner_2();
  pfrelr corner_3();
  pfrelr corner_4();
  microprocessor u_microprocessor_core(.clk (clk), .rst (rst),
       .mem_bank_sel (mem_bank_sel), .dbg_sel (dbg_sel), .CLKOUT
       (UNCONNECTED174), .dbg_out (dbg_out));
  pc3d01 pc3d01_clk(.PAD (clk_pad), .CIN (clk));
  pc3d01 pc3d01_dbg_sel_0(.PAD (dbg_sel_pad[0]), .CIN (dbg_sel[0]));
  pc3d01 pc3d01_dbg_sel_1(.PAD (dbg_sel_pad[1]), .CIN (dbg_sel[1]));
  pc3d01 pc3d01_mem_bank_sel_0(.PAD (mem_bank_sel_pad[0]), .CIN
       (mem_bank_sel[0]));
  pc3d01 pc3d01_mem_bank_sel_1(.PAD (mem_bank_sel_pad[1]), .CIN
       (mem_bank_sel[1]));
  pc3d01 pc3d01_rst(.PAD (rst_pad), .CIN (rst));
  pc3o05 pc3o05_CLKOUT(.I (clk), .PAD (CLKOUT_pad));
  pc3o05 pc3o05_dbg_out_0(.I (dbg_out[0]), .PAD (dbg_out_pad[0]));
  pc3o05 pc3o05_dbg_out_1(.I (dbg_out[1]), .PAD (dbg_out_pad[1]));
